import { NextRequest } from 'next/server'
import { prisma } from '@/lib/prisma'
import { requireAuth, getTenantId, successResponse, errorResponse } from '@/lib/api'

const TA = ['TENANT_ADMIN', 'SUPER_ADMIN']

// ── Custom department support ─────────────────────────────────────────────────
// Department keys are free-form strings (e.g. IT, FINANCE, LIBRARY, SECURITY).
// The Department enum was removed from schema — all fields are now String.
// Tenants can add any custom department key up to their license maxDepartments.
// ─────────────────────────────────────────────────────────────────────────────

export async function GET(req: NextRequest) {
  // All authenticated tenant users need to read departments (for ticket form dropdowns)
  const { error, session } = await requireAuth()
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const depts = await prisma.departmentConfig.findMany({
    where: { tenantId },
    orderBy: { createdAt: 'asc' },
  })
  return successResponse(depts)
}

export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const body = await req.json()
  const { department, label, email } = body

  if (!department || !label) return errorResponse('department key and label are required')

  // Normalize key: uppercase, underscores only
  const deptKey = String(department).toUpperCase().replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '')
  if (!deptKey) return errorResponse('Invalid department key')

  // Check for duplicate within this tenant
  const existing = await prisma.departmentConfig.findFirst({
    where: { tenantId, department: deptKey },
  })
  if (existing) return errorResponse(`Department "${deptKey}" already exists`, 409)

  const dept = await prisma.departmentConfig.create({
    data: {
      tenantId,
      department: deptKey,
      label: String(label).trim(),
      email: email ? String(email).trim() : null,
      isActive: true,
    },
  })

  return successResponse(dept, 201)
}

export async function PATCH(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const body = await req.json()
  const { id, department, label, email, isActive, icon } = body

  if (!id && !department) return errorResponse('id or department required')

  const where = id ? { id, tenantId } : { tenantId, department: String(department).toUpperCase() }

  const dept = await prisma.departmentConfig.updateMany({
    where,
    data: {
      ...(label    !== undefined ? { label: String(label).trim() }        : {}),
      ...(email    !== undefined ? { email: email ? String(email).trim() : null } : {}),
      ...(isActive !== undefined ? { isActive: Boolean(isActive) }        : {}),
      ...(icon     !== undefined ? { icon: icon || null }                 : {}),
    },
  })

  if (dept.count === 0) return errorResponse('Department not found', 404)
  return successResponse({ updated: dept.count })
}

export async function DELETE(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const { searchParams } = new URL(req.url)
  const department = searchParams.get('department')
  const id = searchParams.get('id')
  if (!department && !id) return errorResponse('department or id required')

  const deptKey = department ? String(department).toUpperCase() : undefined

  // Block deletion if active tickets exist in this department
  const activeTickets = await prisma.ticket.count({
    where: {
      tenantId,
      ...(deptKey ? { department: deptKey as any } : {}),
      status: { notIn: ['RESOLVED', 'CLOSED'] },
    },
  })
  if (activeTickets > 0) {
    return errorResponse(
      `Cannot remove department — ${activeTickets} active ticket${activeTickets > 1 ? 's' : ''} still open. Resolve or reassign them first.`,
      409,
    )
  }

  const where: any = { tenantId }
  if (deptKey) where.department = deptKey
  if (id) where.id = id

  await prisma.departmentConfig.deleteMany({ where })
  return successResponse({ deleted: true })
}
